import{c as e,Q as a,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Agent Harness Engineering: The Rise of the AI Control Plane","description":"","frontmatter":{"title":"Agent Harness Engineering: The Rise of the AI Control Plane","authors":"Adnan Masood","source":"https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2026-04-adnan-masood-agent-control-plane.md","filePath":"research/agent-harness/references/2026-04-adnan-masood-agent-control-plane.md","lastUpdated":1779796674000}'),o={name:"research/agent-harness/references/2026-04-adnan-masood-agent-control-plane.md"};function s(d,t,l,i,h,c){return a(),r("div",null,[...t[0]||(t[0]=[n('<h1 id="agent-harness-engineering-the-rise-of-the-ai-control-plane" tabindex="-1">Agent Harness Engineering: The Rise of the AI Control Plane <a class="header-anchor" href="#agent-harness-engineering-the-rise-of-the-ai-control-plane" aria-label="Permalink to &quot;Agent Harness Engineering: The Rise of the AI Control Plane&quot;">​</a></h1><ul><li><strong>作者</strong>: Adnan Masood</li><li><strong>平台</strong>: Medium</li><li><strong>URL</strong>: <a href="https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d" target="_blank" rel="noreferrer">https://medium.com/@adnanmasood/agent-harness-engineering-the-rise-of-the-ai-control-plane-938ead884b1d</a></li><li><strong>發表</strong>: 2026-04</li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>重要性</strong>: Priority B — 以 Control Plane 視角重新定義 harness 工程；含企業數據支持</li></ul><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><p>「定義 AI 的瓶頸已從模型能力轉向 agent harness。」</p><p>模型是無狀態的 token 預測器；harness 是運行時基礎設施，負責工具分派、context 管理和安全強制。</p><p><strong>關鍵統計</strong>: 企業 AI 失敗的 <strong>65% 源自 harness 層缺陷</strong>，而非模型推理限制。</p><hr><h2 id="_5-層-control-plane-架構" tabindex="-1">5 層 Control Plane 架構 <a class="header-anchor" href="#_5-層-control-plane-架構" aria-label="Permalink to &quot;5 層 Control Plane 架構&quot;">​</a></h2><table tabindex="0"><thead><tr><th>層次</th><th>名稱</th><th>職責</th></tr></thead><tbody><tr><td>1</td><td><strong>Context Management</strong></td><td>系統提示、對話歷史、文件檢索、記憶體壓縮</td></tr><tr><td>2</td><td><strong>Tool/Function Calling</strong></td><td>能力暴露（APIs、程式碼執行、MCP servers）、請求路由</td></tr><tr><td>3</td><td><strong>Execution Loop</strong></td><td>Observe-Think-Act 週期，管理狀態轉換與錯誤恢復</td></tr><tr><td>4</td><td><strong>State &amp; Memory</strong></td><td>Scratchpads、任務清單、跨 session 持久記憶體</td></tr><tr><td>5</td><td><strong>Safety &amp; Observability</strong></td><td>防護欄、權限檢查、審批閘道、審計日誌、追蹤</td></tr></tbody></table><hr><h2 id="核心洞見" tabindex="-1">核心洞見 <a class="header-anchor" href="#核心洞見" aria-label="Permalink to &quot;核心洞見&quot;">​</a></h2><h3 id="成本優化視角" tabindex="-1">成本優化視角 <a class="header-anchor" href="#成本優化視角" aria-label="Permalink to &quot;成本優化視角&quot;">​</a></h3><p>正確的 cache 管理能將 token 成本降低十倍（$3.00/MTok → $0.30/MTok），無需改變模型。</p><h3 id="確定性優先於自主性" tabindex="-1">確定性優先於自主性 <a class="header-anchor" href="#確定性優先於自主性" aria-label="Permalink to &quot;確定性優先於自主性&quot;">​</a></h3><p>「混亂的 swarms」被邊界清晰的 workflow 和人類檢查點取代。</p><h3 id="環境可讀性" tabindex="-1">環境可讀性 <a class="header-anchor" href="#環境可讀性" aria-label="Permalink to &quot;環境可讀性&quot;">​</a></h3><p>系統應被重新設計為對 agent 本質可導航，減少方向迷茫造成的 token 浪費。</p><h3 id="架構模式" tabindex="-1">架構模式 <a class="header-anchor" href="#架構模式" aria-label="Permalink to &quot;架構模式&quot;">​</a></h3><ul><li><strong>Plan-Execute-Verify 迴圈</strong>: 分離規劃、執行、驗證</li><li><strong>Reasoning Sandwich</strong>: 複雜模型用於規劃/驗證，廉價模型用於中間工作</li><li><strong>Ralph Loop</strong>: 自動恢復機制</li></ul><h3 id="買-vs-建策略" tabindex="-1">買 vs 建策略 <a class="header-anchor" href="#買-vs-建策略" aria-label="Permalink to &quot;買 vs 建策略&quot;">​</a></h3><ul><li><strong>買（Buy）</strong>: 商品化基礎設施（向量 DB、框架）</li><li><strong>建（Build）</strong>: 領域特定工具、評估資料集、環境地圖</li></ul><h3 id="標準化" tabindex="-1">標準化 <a class="header-anchor" href="#標準化" aria-label="Permalink to &quot;標準化&quot;">​</a></h3><p>採用 MCP（Model Context Protocol）和 A2A（Agent-to-Agent）協議統一工具介面。</p><hr><h2 id="與其他-harness-文章的差異" tabindex="-1">與其他 Harness 文章的差異 <a class="header-anchor" href="#與其他-harness-文章的差異" aria-label="Permalink to &quot;與其他 Harness 文章的差異&quot;">​</a></h2><table tabindex="0"><thead><tr><th>面向</th><th>本文（Masood）</th><th>HumanLayer</th><th>Anthropic</th></tr></thead><tbody><tr><td>視角</td><td>Control Plane 架構</td><td>實作配置問題</td><td>長運行任務設計</td></tr><tr><td>重點</td><td>成本優化、安全</td><td>Ratchet 積累</td><td>Planner-Evaluator 分離</td></tr><tr><td>數據</td><td>企業失敗率統計</td><td>Terminal-Bench 量化</td><td>遊戲引擎案例</td></tr></tbody></table><hr><h2 id="與本-workspace-的對應" tabindex="-1">與本 Workspace 的對應 <a class="header-anchor" href="#與本-workspace-的對應" aria-label="Permalink to &quot;與本 Workspace 的對應&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Masood 的 5 層</th><th>Workspace 的實現</th></tr></thead><tbody><tr><td>Context Management</td><td>context-management.md + /compact 規則</td></tr><tr><td>Tool/Function Calling</td><td>ToolSearch + MCP tools</td></tr><tr><td>Execution Loop</td><td>agentic loop + hooks</td></tr><tr><td>State &amp; Memory</td><td>Auto Memory + ACTIVE_TASK.md</td></tr><tr><td>Safety &amp; Observability</td><td>security-hygiene.md + PreToolUse hook</td></tr></tbody></table>',30)])])}const p=e(o,[["render",s]]);export{m as __pageData,p as default};
